import React, { useState, useEffect, useRef } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import Preloader from './components/Preloader';

// Regular pages
import HomePage from './pages/HomePage';
import CoursesPage from './pages/CoursesPage';
import AboutPage from './pages/AboutPage';
import NewsPage from './pages/NewsPage';
import ApplyPage from './pages/ApplyPage';
import ContactPage from './pages/ContactPage';
import CareerServicesPage from './pages/CareerServicesPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';

// Admin pages
import AdminLayout from './components/layout/AdminLayout';
import AdminDashboard from './pages/admin/Dashboard';
import StudentsTable from './components/admin/StudentsTable';

// Student pages
import StudentLayout from './components/layout/StudentLayout';
import Dashboard from './pages/student/Dashboard';
import StudentProfile from './pages/student/Profile';

// Styles
import 'material-icons/iconfont/material-icons.css';
import 'aos/dist/aos.css';
import '@fortawesome/fontawesome-free/css/all.min.css';
// Import antd styles
import 'antd/dist/antd.css'; // or 'antd/dist/antd.min.css'
import AOS from 'aos';

function App() {
    const [loading, setLoading] = useState(true);
    const mainRef = useRef(null);

    useEffect(() => {
        const timer = setTimeout(() => setLoading(false), 3000);
        return () => clearTimeout(timer);
    }, []);

    useEffect(() => {
    AOS.init({
        duration: 1000,
        once: true
    });
    }, []);

    useEffect(() => {
        if (!loading && window.anime && mainRef.current) {
            window.anime({
                targets: mainRef.current,
                opacity: [0, 1],
                translateY: [40, 0],
                duration: 800,
                easing: 'easeOutQuad'
            });
        }
    }, [loading]);

    if (loading) {
        return <Preloader />;
    }

    return (
        <Router>
            <Header />
            <main ref={mainRef}>
                <Switch>
                    <Route path="/" exact component={HomePage} />
                    <Route path="/courses" component={CoursesPage} />
                    <Route path="/about" component={AboutPage} />
                    <Route path="/news" component={NewsPage} />
                    <Route path="/career-services" component={CareerServicesPage} />
                    <Route path="/apply" component={ApplyPage} />
                    <Route path="/contact" component={ContactPage} />
                    <Route path="/login" component={LoginModal} />
                    <Route path="/register" component={LoginModal} />
                </Switch>
            </main>
            <Footer />
            <LoginModal />
        </Router>
    );
}

export default App;
